const items = $input.all();

console.log('\n═══════════════════════════════════════════════════');
console.log('📊 STRUCTURATION NOTIFICATIONS - SALARIÉS (XSAL) + TELEGRAM');
console.log('═══════════════════════════════════════════════════');
console.log(`Lignes reçues: ${items.length}`);

const notifications = {};

items.forEach(item => {
  const d = item.json;

  let dest, codeKey, typeKey;

  if (d.niveau_escalade === 'PDG') {
    dest = {
      code: d.code_pdg, nom: d.nom_pdg, prenom: d.prenom_pdg,
      email: d.email_pdg, telephone: d.telephone_pdg,
      chat_id: d.chat_id_pdg, langue: d.langue_pdg, bot: d.bot_pdg
    };
    codeKey = d.code_pdg; typeKey = 'PDG';

  } else if (d.niveau_escalade === 'DGA') {
    dest = {
      code: d.code_dga, nom: d.nom_dga, prenom: d.prenom_dga,
      email: d.email_dga, telephone: d.telephone_dga,
      chat_id: d.chat_id_dga, langue: d.langue_dga, bot: d.bot_dga
    };
    codeKey = d.code_dga; typeKey = 'DGA';

  } else if (d.niveau_escalade === 'BAALLAH') {
    dest = {
      code: d.code_baallah, nom: d.nom_baallah, prenom: d.prenom_baallah,
      email: d.email_baallah, telephone: d.telephone_baallah,
      chat_id: d.chat_id_baallah, langue: d.langue_baallah, bot: d.bot_baallah
    };
    codeKey = d.code_baallah; typeKey = 'BAALLAH';

  } else if (d.niveau_escalade === 'SUPERIEUR') {
    dest = {
      code: d.code_sup_createur, nom: d.nom_sup_createur, prenom: d.prenom_sup_createur,
      email: d.email_sup_createur, telephone: d.tel_sup_createur,
      chat_id: d.chat_id_superieur, langue: d.langue_superieur, bot: d.bot_superieur
    };
    codeKey = d.code_sup_createur; typeKey = 'SUPERIEUR';

  } else if (d.niveau_escalade === 'SALARIE') {
    dest = {
      code: d.code_salarie, nom: d.nom, prenom: d.prenom,
      email: d.email, telephone: d.telephone,
      chat_id: d.chat_id_salarie, langue: d.langue_salarie, bot: d.bot_salarie
    };
    codeKey = d.code_salarie; typeKey = 'SALARIE';

  } else if (d.niveau_escalade === 'FARHAT') {
    dest = {
      code: d.code_farhat, nom: d.nom_farhat, prenom: d.prenom_farhat,
      email: d.email_farhat, telephone: d.telephone_farhat,
      chat_id: d.chat_id_farhat, langue: d.langue_farhat, bot: d.bot_farhat
    };
    codeKey = d.code_farhat; typeKey = 'FARHAT';

  } else {
    return;
  }

  const cleKey = `${typeKey}_${codeKey}`;

  if (!notifications[cleKey]) {
    notifications[cleKey] = {
      destinataire_principal: dest,
      type_destinataire: typeKey,
      niveau_escalade: d.niveau_escalade,
      salarie_info: {
        code: d.code_salarie, nom: d.nom, prenom: d.prenom,
        email: d.email, telephone: d.telephone,
        chat_id: d.chat_id_salarie, langue: d.langue_salarie, bot: d.bot_salarie
      },
      superieur: {
        code: d.code_sup_createur, nom: d.nom_sup_createur, prenom: d.prenom_sup_createur,
        email: d.email_sup_createur, telephone: d.tel_sup_createur,
        chat_id: d.chat_id_superieur, langue: d.langue_superieur, bot: d.bot_superieur
      },
      pdg: {
        code: d.code_pdg, nom: d.nom_pdg, prenom: d.prenom_pdg,
        email: d.email_pdg, telephone: d.telephone_pdg,
        chat_id: d.chat_id_pdg, langue: d.langue_pdg, bot: d.bot_pdg
      },
      dga: {
        code: d.code_dga, nom: d.nom_dga, prenom: d.prenom_dga,
        email: d.email_dga, telephone: d.telephone_dga,
        chat_id: d.chat_id_dga, langue: d.langue_dga, bot: d.bot_dga
      },
      farhat: {
        code: d.code_farhat, nom: d.nom_farhat, prenom: d.prenom_farhat,
        email: d.email_farhat, telephone: d.telephone_farhat,
        chat_id: d.chat_id_farhat, langue: d.langue_farhat, bot: d.bot_farhat
      },
      baallah: {
        code: d.code_baallah, nom: d.nom_baallah, prenom: d.prenom_baallah,
        email: d.email_baallah, telephone: d.telephone_baallah,
        chat_id: d.chat_id_baallah, langue: d.langue_baallah, bot: d.bot_baallah
      },
      salaries: []
    };
  }

  notifications[cleKey].salaries.push({
    code_salarie: d.code_salarie,
    nom: d.nom, prenom: d.prenom,
    email: d.email, telephone: d.telephone,
    matricule: d.matricule,
    date_creation: d.date_creation,
    date_controle: d.date_controle,
    date_limite: d.date_limite,
    jours_depuis_creation: d.jours_depuis_creation,
    jours_restants: d.jours_restants,
    delai_int: d.delai_int,
    seuil_dga: d.seuil_dga,
    createur: {
      code: d.code_createur, nom: d.nom_createur, prenom: d.prenom_createur,
      email: d.email_createur, telephone: d.tel_createur
    }
  });
});

const resultats = Object.values(notifications).map(notif => {
  const total = notif.salaries.length;
  const joursMin = Math.min(...notif.salaries.map(s => s.jours_restants));
  const joursMax = Math.max(...notif.salaries.map(s => s.jours_restants));
  const delaiInt = notif.salaries[0]?.delai_int || 30;
  const seuilDga = notif.salaries[0]?.seuil_dga || Math.floor(delaiInt / 2);

  return {
    destinataire_principal: notif.destinataire_principal,
    type_destinataire: notif.type_destinataire,
    niveau_escalade: notif.niveau_escalade,
    salarie_info: notif.salarie_info,
    superieur: notif.superieur,
    pdg: notif.pdg,
    dga: notif.dga,
    farhat: notif.farhat,
    baallah: notif.baallah,
    salaries: notif.salaries,
    statistiques: {
      total_salaries: total,
      jours_min: joursMin,
      jours_max: joursMax,
      delai_int: delaiInt,
      seuil_dga: seuilDga
    },
    meta: {
      date_traitement: new Date().toISOString(),
      peut_envoyer_email: !!notif.destinataire_principal.email,
      peut_envoyer_telegram: !!notif.destinataire_principal.chat_id,
      langue_message: notif.destinataire_principal.langue || 'FRA'
    }
  };
});

console.log(`\n✅ Groupes structurés: ${resultats.length}`);
['PDG','DGA','BAALLAH','SUPERIEUR','SALARIE','FARHAT'].forEach(t => {
  console.log(`  - ${t}: ${resultats.filter(r => r.type_destinataire === t).length}`);
});
console.log('═══════════════════════════════════════════════════\n');

return resultats.map(r => ({ json: r }));

const inputData = $input.all();

const TEMPLATES = {
  FRA: {
    sujet: {
      PDG:      '🔴 ALERTE URGENTE - Salariés sans matricule/contrat',
      DGA:      '🟠 INFO DGA - Salariés à mi-délai sans matricule',
      BAALLAH:  '🟠 INFO - Salariés à mi-délai sans matricule',
      SUPERIEUR:'🟠 IMPORTANT - Salariés sans matricule/contrat',
      SALARIE:  '🟡 Rappel - Votre dossier est en attente de complétion',
      FARHAT:   '🔵 INFO PRÉVENTIVE - Salariés à surveiller'
    },
    salutation: 'Bonjour',
    intro: {
      PDG:      "ALERTE URGENTE - Les salariés suivants n'ont toujours pas de matricule ou contrat attaché",
      DGA:      'Information - Les salariés suivants ont atteint la moitié de leur délai sans traitement',
      BAALLAH:  'Information - Les salariés suivants ont atteint la moitié de leur délai sans traitement',
      SUPERIEUR:'Les salariés suivants requièrent votre attention en priorité',
      SALARIE:  'Rappel concernant votre dossier en attente de traitement',
      FARHAT:   'Information préventive - Les salariés suivants approchent de leur délai limite'
    },
    section_stats: 'STATISTIQUES',
    section_liste: 'LISTE DES SALARIÉS CONCERNÉS',
    total: 'Total salariés',
    delai_min: 'Délai minimum restant',
    delai_total: 'Délai total paramétré',
    seuil_dga: 'Seuil mi-délai',
    jours: 'jour(s)',
    matricule: 'Matricule',
    date_creation: 'Date création',
    jours_restants: 'Jours restants',
    date_limite: 'Date limite',
    date_controle: 'Date contrôle',
    createur: 'Créé par',
    urgent: 'URGENT - Traitement immédiat requis',
    instruction: 'Veuillez traiter ces dossiers dans les meilleurs délais.',
    instruction_dga: 'Ces dossiers ont dépassé la moitié du délai autorisé. Merci de vous assurer que les actions correctives sont engagées.',
    cordialement: 'Cordialement',
    signature: 'Service SI/IA - Jbel Annour',
    message_auto: 'Message automatique',
    ne_pas_repondre: 'Merci de ne pas répondre à cet email'
  }
};

function formaterDate(d) {
  if (!d) return 'N/A';
  return new Date(d).toLocaleDateString('fr-FR', { year: 'numeric', month: '2-digit', day: '2-digit' });
}

function emoji(j) {
  if (j <= 2) return '🔴';
  if (j === 3) return '🟠';
  if (j === 4) return '🟡';
  if (j <= 8) return '🔵';
  return '🟢';
}

function genererEmail(data) {
  const T = TEMPLATES['FRA'];
  const dest = data.destinataire_principal;
  const stats = data.statistiques;
  const type = data.type_destinataire;

  let subject = `${T.sujet[type]} - ${stats.total_salaries} salarié(s)`;

  let body = `${T.salutation} ${dest.prenom} ${dest.nom},\n\n`;
  body += `${T.intro[type]}\n\n`;
  body += `═══════════════════════════════════════════════════════════════\n`;
  body += `📊 ${T.section_stats}\n`;
  body += `═══════════════════════════════════════════════════════════════\n\n`;
  body += `${emoji(stats.jours_min)} Niveau escalade : ${data.niveau_escalade}\n`;
  body += `${T.total} : ${stats.total_salaries}\n`;
  body += `${T.delai_min} : ${stats.jours_min} ${T.jours}\n`;
  body += `${T.delai_total} : ${stats.delai_int} ${T.jours}\n`;
  if (type === 'DGA' || type === 'BAALLAH') body += `${T.seuil_dga} : ${stats.seuil_dga} ${T.jours}\n`;

  body += `\n═══════════════════════════════════════════════════════════════\n`;
  body += `👥 ${T.section_liste}\n`;
  body += `═══════════════════════════════════════════════════════════════\n\n`;

  data.salaries.forEach((s, i) => {
    body += `${i + 1}. ${emoji(s.jours_restants)} ${s.prenom} ${s.nom} (${s.code_salarie})\n`;
    body += `   📋 ${T.matricule} : ${s.matricule && s.matricule.trim() ? s.matricule : 'Non attribué'}\n`;
    body += `   📅 ${T.date_creation} : ${formaterDate(s.date_creation)}\n`;
    if (s.date_controle && !String(s.date_controle).includes('1753')) {
      body += `   🗓️ ${T.date_controle} : ${formaterDate(s.date_controle)}\n`;
    }
    body += `   ⏰ ${T.jours_restants} : ${s.jours_restants} ${T.jours} (${T.date_limite} : ${formaterDate(s.date_limite)})\n`;
    body += `   👤 ${T.createur} : ${s.createur.prenom} ${s.createur.nom}\n`;
    if (s.jours_restants <= 2) body += `   🚨 ${T.urgent}\n`;
    body += `\n`;
  });

  body += `═══════════════════════════════════════════════════════════════\n`;
  if (stats.jours_min <= 2) body += `🚨 ${T.urgent}\n`;
  else if (type === 'DGA' || type === 'BAALLAH') body += `📌 ${T.instruction_dga}\n`;
  else body += `📌 ${T.instruction}\n`;
  body += `═══════════════════════════════════════════════════════════════\n\n`;
  body += `${T.cordialement},\n\n${T.signature}\n\n`;
  body += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
  body += `🤖 ${T.message_auto} - ${formaterDate(new Date().toISOString())}\n`;
  body += `${T.ne_pas_repondre}\n`;

  return { subject, body };
}

function genererTelegram(data) {
  const T = TEMPLATES['FRA'];
  const dest = data.destinataire_principal;
  const stats = data.statistiques;
  const type = data.type_destinataire;

  let text = `${emoji(stats.jours_min)} *${T.sujet[type]}*\n`;
  text += `━━━━━━━━━━━━━━━━━━━━━\n\n`;
  text += `👤 *${dest.prenom} ${dest.nom}*\n\n`;
  text += `📊 *${T.section_stats}*\n`;
  text += `${T.total}: *${stats.total_salaries}*\n`;
  text += `${T.delai_min}: *${stats.jours_min} ${T.jours}*\n`;
  if (type === 'DGA' || type === 'BAALLAH') text += `${T.seuil_dga}: *${stats.seuil_dga} ${T.jours}*\n`;
  text += `\n👥 *${T.section_liste}*\n\n`;

  data.salaries.slice(0, 5).forEach((s, i) => {
    text += `${i + 1}. ${emoji(s.jours_restants)} *${s.prenom} ${s.nom}* (${s.code_salarie})\n`;
    text += `   📋 Mat: ${s.matricule && s.matricule.trim() ? s.matricule : 'Non attribué'}\n`;
    text += `   ⏰ ${s.jours_restants} ${T.jours} restant(s)\n\n`;
  });
  if (data.salaries.length > 5) text += `... et ${data.salaries.length - 5} autre(s) salarié(s)\n\n`;
  if (stats.jours_min <= 2) text += `🚨 *${T.urgent}*\n`;
  else if (type === 'DGA' || type === 'BAALLAH') text += `📌 ${T.instruction_dga}\n`;
  else text += `📌 ${T.instruction}\n`;
  text += `\n🤖 _${T.message_auto} - ${formaterDate(new Date().toISOString())}_\n`;

  return { text, parse_mode: 'Markdown' };
}

// ─────────────────────────────────────────────────────────────
// DISPATCH : principal + CC Telegram (PDG/SUPERIEUR)
// ─────────────────────────────────────────────────────────────
const results = [];

inputData.forEach(item => {
  const data = item.json;
  const emailMsg    = genererEmail(data);
  const telegramMsg = genererTelegram(data);

  // Message principal
  results.push({
    json: {
      ...data,
      messages: { email: emailMsg, telegram: telegramMsg },
      type_envoi: 'PRINCIPAL',
      destinataire_final: data.destinataire_principal,
      meta: { ...data.meta, date_generation: new Date().toISOString() }
    }
  });

  // CC Telegram : PDG → copie supérieur
  if (data.type_destinataire === 'PDG' && data.superieur?.chat_id) {
    results.push({ json: {
      ...data,
      messages: { email: emailMsg, telegram: telegramMsg },
      type_envoi: 'CC',
      destinataire_final: data.superieur,
      cc_pour_profil: 'SUPERIEUR',
      meta: { ...data.meta, date_generation: new Date().toISOString() }
    }});
  }

  // CC Telegram : PDG → copie salarié
  if (data.type_destinataire === 'PDG' && data.salarie_info?.chat_id) {
    results.push({ json: {
      ...data,
      messages: { email: emailMsg, telegram: telegramMsg },
      type_envoi: 'CC',
      destinataire_final: data.salarie_info,
      cc_pour_profil: 'SALARIE',
      meta: { ...data.meta, date_generation: new Date().toISOString() }
    }});
  }

  // CC Telegram : SUPERIEUR → copie salarié
  if (data.type_destinataire === 'SUPERIEUR' && data.salarie_info?.chat_id) {
    results.push({ json: {
      ...data,
      messages: { email: emailMsg, telegram: telegramMsg },
      type_envoi: 'CC',
      destinataire_final: data.salarie_info,
      cc_pour_profil: 'SALARIE',
      meta: { ...data.meta, date_generation: new Date().toISOString() }
    }});
  }
});

console.log(`\n✅ Messages générés: ${results.length}`);
console.log(`  - Principaux: ${results.filter(r => r.json.type_envoi === 'PRINCIPAL').length}`);
console.log(`  - CC Telegram: ${results.filter(r => r.json.type_envoi === 'CC').length}`);
['PDG','DGA','BAALLAH','SUPERIEUR','SALARIE','FARHAT'].forEach(t => {
  console.log(`  - ${t}: ${results.filter(r => r.json.type_destinataire === t).length}`);
});
console.log('═══════════════════════════════════════════════════\n');

return results;
